# Let's write a small C# program to parse the binlog
mkdir -p /tmp/binlog-reader && cd /tmp/binlog-reader && cat > binlog-reader.csproj << 'EOF'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net9.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.405" />
  </ItemGroup>
</Project>
EOF

cat > Program.cs << 'EOF'
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("/tmp/sv-3cba129d35df44c6a19e2155ea385e1e/build.binlog");

Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCESS" : "FAILED") + " ===\n");

// Print all errors
Console.WriteLine("=== ALL ERRORS ===");
var errors = build.FindChildrenRecursive<Error>().ToList();
foreach (var error in errors)
{
    var project = error.GetNearestParent<Project>();
    var projectName = project?.Name ?? "unknown";
    Console.WriteLine($"[{projectName}] {error.Code}: {error.Text}");
    if (!string.IsNullOrEmpty(error.File))
        Console.WriteLine($"  File: {error.File}({error.LineNumber},{error.ColumnNumber})");
    Console.WriteLine();
}

Console.WriteLine($"\nTotal errors: {errors.Count}");

// Print warnings that might be relevant
Console.WriteLine("\n=== WARNINGS (first 20) ===");
var warnings = build.FindChildrenRecursive<Warning>().Take(20).ToList();
foreach (var w in warnings)
{
    var project = w.GetNearestParent<Project>();
    Console.WriteLine($"[{project?.Name ?? "?"}] {w.Code}: {w.Text}");
}
EOF

