cd /tmp/binlog-reader && cat > Program.cs << 'EOF'
using System;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("/tmp/sv-3cba129d35df44c6a19e2155ea385e1e/build.binlog");

// Get all projects and their results
Console.WriteLine("=== PROJECT BUILD RESULTS ===");
var projects = build.FindChildrenRecursive<Project>().ToList();
foreach (var p in projects)
{
    Console.WriteLine($"  {p.Name} - Succeeded: {p.Succeeded}");
}

// Check for dependency failures / cascading
Console.WriteLine("\n=== PACKAGE REFERENCES in Services.csproj ===");
var svcProject = projects.FirstOrDefault(p => p.Name == "Services.csproj");
if (svcProject != null)
{
    // Look for ResolvePackageAssets or similar
    var items = svcProject.FindChildrenRecursive<Item>().Where(i => i.Name == "PackageReference").ToList();
    foreach (var item in items)
        Console.WriteLine($"  PackageReference: {item.Text}");

    // Also check AddItem for package references
    var addItems = svcProject.FindChildrenRecursive<AddItem>().Where(i => i.Name == "PackageReference").ToList();
    foreach (var ai in addItems)
    {
        Console.WriteLine($"  AddItem PackageReference: {ai.Text}");
        foreach (var child in ai.Children)
            Console.WriteLine($"    -> {child}");
    }
}

// Look at the source file content if captured
Console.WriteLine("\n=== CSC COMMAND LINE (Services) ===");
var cscTask = svcProject?.FindChildrenRecursive<Task>().FirstOrDefault(t => t.Name == "Csc");
if (cscTask != null)
{
    var commandLine = cscTask.FindChildrenRecursive<Property>().FirstOrDefault(p => p.Name == "CommandLineArguments");
    if (commandLine != null)
    {
        // Look for /reference args
        var refs = commandLine.Value.Split(' ').Where(a => a.StartsWith("/reference:")).ToList();
        Console.WriteLine($"  Total /reference args: {refs.Count}");
        var newtonsoftRef = refs.FirstOrDefault(r => r.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase));
        Console.WriteLine($"  Newtonsoft ref: {newtonsoftRef ?? "NOT FOUND"}");
    }
}

// Check restore output
Console.WriteLine("\n=== RESTORE MESSAGES ===");
var restoreMessages = build.FindChildrenRecursive<Message>()
    .Where(m => m.Text != null && m.Text.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase))
    .Take(10).ToList();
foreach (var m in restoreMessages)
    Console.WriteLine($"  {m.Text}");

// Check all projects that failed
Console.WriteLine("\n=== FAILED PROJECTS ===");
foreach (var p in projects.Where(p => !p.Succeeded))
    Console.WriteLine($"  {p.Name} ({p.ProjectFile})");
EOF
