            Console.WriteLine($"    Found: {node.GetType().Name}: {str}");
        if (str != null && str.Contains("PackageReference", StringComparison.OrdinalIgnoreCase))
            Console.WriteLine($"    PkgRef: {node.GetType().Name}: {str}");
    }
}

